import React, { useEffect, useState } from 'react';
import { listarUsuarios, listarRoles, registrarUsuario, obtenerFicha, listarConsultasPorUsuario } from '../service/api';

const tag = (color, texto) => {
  const bg = color==='red'?'#FCEBEB':color==='amber'?'#FAEEDA':color==='blue'?'#E6F1FB':color==='teal'?'#E1F5EE':'var(--color-background-secondary)';
  const cl = color==='red'?'#A32D2D':color==='amber'?'#854F0B':color==='blue'?'#185FA5':color==='teal'?'#0F6E56':'var(--color-text-secondary)';
  return <span style={{ background:bg, color:cl, borderRadius:20, padding:'3px 10px', fontSize:12, fontWeight:500, display:'inline-block', margin:'2px' }}>{texto}</span>;
};

const tags = (str, color) => str
  ? str.split(',').map(s=>s.trim()).filter(Boolean).map(s=><span key={s}>{tag(color,s)}</span>)
  : <span style={{fontSize:13,color:'var(--color-text-secondary)'}}>Sin registrar</span>;

function ModalUsuario({ usuario, onClose }) {
  const [tab, setTab] = useState('ficha');
  const [ficha, setFicha] = useState(null);
  const [consultas, setConsultas] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      obtenerFicha(usuario.id).catch(() => null),
      listarConsultasPorUsuario(usuario.id).catch(() => []),
    ]).then(([f, c]) => {
      setFicha(f);
      setConsultas(Array.isArray(c) ? c : []);
    }).finally(() => setLoading(false));
  }, [usuario.id]);

  const nombre = usuario.persona
    ? `${usuario.persona.apellido1||''} ${usuario.persona.apellido2||''}`.trim()
    : usuario.mail.split('@')[0];

  const iniciales = usuario.persona
    ? (usuario.persona.apellido1?.[0]||'') + (usuario.persona.apellido2?.[0]||'')
    : usuario.mail[0].toUpperCase();

  const imc = ficha?.estatura && ficha?.peso
    ? (ficha.peso / ((ficha.estatura/100)**2)).toFixed(1) : null;

  const badgeEstado = (estado) => {
    const map = { PENDIENTE:['amber','⏳'], AGENDADA:['blue','📅'], ATENDIDA:['teal','✅'], CANCELADA:['red','❌'], REASIGNADA:['blue','🔄'] };
    const [color, icon] = map[estado] || ['gray', '•'];
    return tag(color, `${icon} ${estado}`);
  };

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:1000, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}
      onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{ background:'var(--color-background-primary)', borderRadius:16, width:'100%', maxWidth:620, maxHeight:'85vh', display:'flex', flexDirection:'column', border:'0.5px solid var(--color-border-tertiary)' }}>

        {/* Header */}
        <div style={{ padding:'1.25rem 1.5rem', borderBottom:'0.5px solid var(--color-border-tertiary)', display:'flex', alignItems:'center', gap:14 }}>
          <div style={{ width:48, height:48, borderRadius:'50%', background:'linear-gradient(135deg,#2563EB,#0D9488)', display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:700, fontSize:16, flexShrink:0 }}>{iniciales}</div>
          <div style={{ flex:1 }}>
            <div style={{ fontWeight:600, fontSize:16 }}>{nombre}</div>
            <div style={{ fontSize:13, color:'var(--color-text-secondary)' }}>{usuario.id} · {usuario.mail}</div>
          </div>
          <div style={{ display:'flex', gap:8, alignItems:'center' }}>
            {usuario.rol && tag('blue', usuario.rol.tag)}
            {tag(usuario.estado==='ACTIVO'?'teal':'red', usuario.estado)}
            <button onClick={onClose} style={{ width:32, height:32, borderRadius:'50%', border:'0.5px solid var(--color-border-tertiary)', background:'var(--color-background-secondary)', cursor:'pointer', fontSize:16, color:'var(--color-text-secondary)', display:'flex', alignItems:'center', justifyContent:'center' }}>✕</button>
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display:'flex', borderBottom:'0.5px solid var(--color-border-tertiary)', padding:'0 1.5rem' }}>
          {[['ficha','🩺 Ficha médica'],['consultas',`📋 Consultas (${consultas.length})`]].map(([k,l]) => (
            <button key={k} onClick={() => setTab(k)} style={{ padding:'10px 16px', border:'none', background:'none', cursor:'pointer', fontSize:13, fontWeight:tab===k?600:400, color:tab===k?'#2563EB':'var(--color-text-secondary)', borderBottom:tab===k?'2px solid #2563EB':'2px solid transparent', marginBottom:-1 }}>{l}</button>
          ))}
        </div>

        {/* Body */}
        <div style={{ overflowY:'auto', padding:'1.25rem 1.5rem', flex:1 }}>
          {loading ? (
            <div style={{ textAlign:'center', padding:40, color:'var(--color-text-secondary)' }}>Cargando...</div>
          ) : tab==='ficha' ? (
            ficha ? (
              <>
                {/* Stats */}
                <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:10, marginBottom:16 }}>
                  {[
                    ['Estatura', ficha.estatura ? `${ficha.estatura} cm` : '—'],
                    ['Peso', ficha.peso ? `${ficha.peso} kg` : '—'],
                    ['IMC', imc || '—'],
                  ].map(([k,v]) => (
                    <div key={k} style={{ background:'var(--color-background-secondary)', borderRadius:8, padding:'10px 14px', textAlign:'center' }}>
                      <div style={{ fontSize:18, fontWeight:600 }}>{v}</div>
                      <div style={{ fontSize:11, color:'var(--color-text-secondary)' }}>{k}</div>
                    </div>
                  ))}
                </div>

                <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:14 }}>
                  {[
                    ['Grupo sanguíneo', ficha.grupoSanguineo],
                    ['Presión arterial', ficha.presionArterial],
                    ['Frecuencia cardíaca', ficha.frecuenciaCardiaca],
                    ['Glucosa', ficha.glucosa],
                    ['Teléfono', ficha.telefono],
                    ['Dirección', ficha.direccion],
                  ].map(([k,v]) => (
                    <div key={k}>
                      <div style={{ fontSize:11, color:'var(--color-text-secondary)', marginBottom:2 }}>{k}</div>
                      <div style={{ fontSize:14, fontWeight:500 }}>{v || '—'}</div>
                    </div>
                  ))}
                </div>

                <div style={{ borderTop:'0.5px solid var(--color-border-tertiary)', paddingTop:14, marginBottom:12 }}>
                  <div style={{ fontSize:12, color:'var(--color-text-secondary)', marginBottom:6 }}>⚠️ Alergias</div>
                  {tags(ficha.alergias, 'red')}
                </div>
                <div style={{ marginBottom:12 }}>
                  <div style={{ fontSize:12, color:'var(--color-text-secondary)', marginBottom:6 }}>🏥 Condiciones crónicas</div>
                  {tags(ficha.condicionesCronicas, 'amber')}
                </div>
                <div style={{ marginBottom:12 }}>
                  <div style={{ fontSize:12, color:'var(--color-text-secondary)', marginBottom:6 }}>💊 Medicamentos actuales</div>
                  {tags(ficha.medicamentosActuales, 'blue')}
                </div>

                {(ficha.cirugiasPrevias || ficha.antecedentesFamiliares) && (
                  <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:12 }}>
                    {ficha.cirugiasPrevias && <div><div style={{ fontSize:11, color:'var(--color-text-secondary)', marginBottom:4 }}>Cirugías previas</div><div style={{ fontSize:13 }}>{ficha.cirugiasPrevias}</div></div>}
                    {ficha.antecedentesFamiliares && <div><div style={{ fontSize:11, color:'var(--color-text-secondary)', marginBottom:4 }}>Antecedentes familiares</div><div style={{ fontSize:13 }}>{ficha.antecedentesFamiliares}</div></div>}
                  </div>
                )}

                {(ficha.habitoTabaco || ficha.habitoAlcohol) && (
                  <div style={{ display:'flex', gap:8, marginBottom:12 }}>
                    {ficha.habitoTabaco && tag('gray', `🚬 ${ficha.habitoTabaco}`)}
                    {ficha.habitoAlcohol && tag('gray', `🍷 ${ficha.habitoAlcohol}`)}
                  </div>
                )}

                {ficha.emergenciaNombre && (
                  <div style={{ borderTop:'0.5px solid var(--color-border-tertiary)', paddingTop:14 }}>
                    <div style={{ fontSize:12, color:'var(--color-text-secondary)', marginBottom:6 }}>🆘 Contacto de emergencia</div>
                    <div style={{ fontSize:14, fontWeight:500 }}>{ficha.emergenciaNombre} · {ficha.emergenciaTelefono} · {ficha.emergenciaRelacion}</div>
                  </div>
                )}
              </>
            ) : (
              <div style={{ textAlign:'center', padding:40 }}>
                <div style={{ fontSize:40, marginBottom:12 }}>📋</div>
                <div style={{ color:'var(--color-text-secondary)', fontSize:14 }}>Este paciente aún no ha completado su ficha médica.</div>
              </div>
            )
          ) : (
            consultas.length > 0 ? (
              <div>
                {consultas.map(c => (
                  <div key={c.id} style={{ borderBottom:'0.5px solid var(--color-border-tertiary)', padding:'12px 0', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                    <div>
                      <div style={{ fontWeight:500, fontSize:14, marginBottom:4, textTransform:'capitalize' }}>#{c.id} — {c.especialidad}</div>
                      <div style={{ fontSize:12, color:'var(--color-text-secondary)' }}>{c.sintomas?.slice(0,60)}{c.sintomas?.length>60?'...':''}</div>
                    </div>
                    <div style={{ textAlign:'right', flexShrink:0, marginLeft:12 }}>
                      {badgeEstado(c.estado)}
                      <div style={{ fontSize:11, color:'var(--color-text-secondary)', marginTop:4 }}>
                        {c.fechaCreacion ? new Date(c.fechaCreacion).toLocaleDateString('es-CL') : '—'}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div style={{ textAlign:'center', padding:40, color:'var(--color-text-secondary)' }}>Sin consultas registradas.</div>
            )
          )}
        </div>
      </div>
    </div>
  );
}

export default function AdminUsuariosPage() {
  const [usuarios, setUsuarios] = useState([]);
  const [roles,    setRoles]    = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [mostrar,  setMostrar]  = useState(false);
  const [usuarioModal, setUsuarioModal] = useState(null);
  const [form, setForm] = useState({ id:'', mail:'', pass:'', estado:'ACTIVO', rolId:'', apellido1:'', apellido2:'', rut:'' });
  const [creando, setCreando] = useState(false);
  const [error,   setError]   = useState('');
  const [exito,   setExito]   = useState('');
  const [buscar,  setBuscar]  = useState('');

  const cargar = () => {
    setLoading(true);
    Promise.all([listarUsuarios(), listarRoles()])
      .then(([u,r]) => { setUsuarios(Array.isArray(u)?u:[]); setRoles(Array.isArray(r)?r:[]); })
      .finally(() => setLoading(false));
  };
  useEffect(() => { cargar(); }, []);

  const handleCrear = async (e) => {
    e.preventDefault(); setError(''); setExito(''); setCreando(true);
    try {
      const rol = roles.find(r => r.id === form.rolId);
      await registrarUsuario({
        id: form.id, mail: form.mail, pass: form.pass, estado: form.estado,
        fechaRegistro: new Date().toISOString(), rol,
        persona: form.apellido1 ? { id:'PER-'+form.id, rut:form.rut, apellido1:form.apellido1, apellido2:form.apellido2, sexo:'M', fechaNacimiento:'2000-01-01' } : null,
      });
      setExito('Usuario creado correctamente.'); setMostrar(false);
      setForm({ id:'', mail:'', pass:'', estado:'ACTIVO', rolId:'', apellido1:'', apellido2:'', rut:'' });
      cargar();
    } catch { setError('Error al crear. El ID o correo ya puede estar en uso.');
    } finally { setCreando(false); }
  };

  const set = k => e => setForm({ ...form, [k]: e.target.value });

  const usuariosFiltrados = usuarios.filter(u =>
    u.mail?.toLowerCase().includes(buscar.toLowerCase()) ||
    u.id?.toLowerCase().includes(buscar.toLowerCase()) ||
    u.persona?.apellido1?.toLowerCase().includes(buscar.toLowerCase())
  );

  return (
    <div className="page">
      {usuarioModal && <ModalUsuario usuario={usuarioModal} onClose={() => setUsuarioModal(null)} />}

      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:24 }}>
        <h2 className="page-title" style={{ margin:0 }}>👥 Gestión de usuarios</h2>
        <button className="btn btn-primary" onClick={() => setMostrar(!mostrar)}>
          {mostrar ? 'Cancelar' : '+ Nuevo usuario'}
        </button>
      </div>

      {error && <div className="alert alert-error">{error}</div>}
      {exito && <div className="alert alert-success">✅ {exito}</div>}

      {mostrar && (
        <div className="card" style={{ marginBottom:24 }}>
          <h3 style={{ marginBottom:20, fontSize:16 }}>Crear nuevo usuario</h3>
          <form onSubmit={handleCrear}>
            <div className="grid-2">
              <div className="form-group"><label>ID único</label><input className="form-control" value={form.id} onChange={set('id')} placeholder="Ej: USR010" required /></div>
              <div className="form-group"><label>Correo</label><input type="email" className="form-control" value={form.mail} onChange={set('mail')} required /></div>
              <div className="form-group"><label>Contraseña</label><input type="password" className="form-control" value={form.pass} onChange={set('pass')} required /></div>
              <div className="form-group"><label>Rol</label>
                <select className="form-control" value={form.rolId} onChange={set('rolId')} required>
                  <option value="">Selecciona...</option>
                  {roles.map(r => <option key={r.id} value={r.id}>{r.nombre} ({r.tag})</option>)}
                </select>
              </div>
              <div className="form-group"><label>Primer apellido</label><input className="form-control" value={form.apellido1} onChange={set('apellido1')} /></div>
              <div className="form-group"><label>Segundo apellido</label><input className="form-control" value={form.apellido2} onChange={set('apellido2')} /></div>
              <div className="form-group"><label>RUT</label><input className="form-control" value={form.rut} onChange={set('rut')} placeholder="12345678-9" /></div>
            </div>
            <button type="submit" className="btn btn-primary" disabled={creando}>{creando?'Creando...':'Crear usuario'}</button>
          </form>
        </div>
      )}

      {/* Buscador */}
      <div style={{ marginBottom:16 }}>
        <input className="form-control" value={buscar} onChange={e=>setBuscar(e.target.value)} placeholder="🔍 Buscar por nombre, correo o ID..." style={{ maxWidth:400 }} />
      </div>

      {loading ? <div className="spinner">Cargando usuarios...</div> : (
        <div className="card" style={{ padding:0, overflow:'hidden' }}>
          <table className="tabla">
            <thead><tr><th>ID</th><th>Correo</th><th>Nombre</th><th>Rol</th><th>Estado</th><th>Registro</th><th>Ficha</th></tr></thead>
            <tbody>
              {usuariosFiltrados.map(u => (
                <tr key={u.id} style={{ cursor:'pointer' }} onClick={() => setUsuarioModal(u)}>
                  <td style={{ fontFamily:'monospace', fontSize:12 }}>{u.id}</td>
                  <td style={{ color:'#2563EB' }}>{u.mail}</td>
                  <td>{u.persona ? `${u.persona.apellido1||''} ${u.persona.apellido2||''}`.trim() : '—'}</td>
                  <td>{u.rol && tag('blue', u.rol.tag)}</td>
                  <td>{tag(u.estado==='ACTIVO'?'teal':'red', u.estado)}</td>
                  <td style={{ fontSize:13, color:'var(--color-text-secondary)' }}>
                    {u.fechaRegistro ? new Date(u.fechaRegistro).toLocaleDateString('es-CL') : '—'}
                  </td>
                  <td><span style={{ fontSize:18 }}>👁️</span></td>
                </tr>
              ))}
              {usuariosFiltrados.length===0 && <tr><td colSpan={7} style={{ textAlign:'center', padding:32, color:'var(--color-text-secondary)' }}>Sin resultados.</td></tr>}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
